    monkeypatch.setattr(customer_read_service,'list_customer_status',lambda *a,**k:_rows(_staged()));
    e=_write(tmp_path,'e2.json',json.dumps(_exec())); pre=_write(tmp_path,'pre2.txt',_pre()); post=_write(tmp_path,'post2.txt',_post()); a=_write(tmp_path,'a2.json','x'); p=_write(tmp_path,'p2.json','y')
